// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Place helper components here if needed

type ForecastItem = {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
};

function getConditionIcon(condition: string): string {
  const normalized = condition.toLowerCase();
  if (normalized.includes('thunder')) return '⛈️';
  if (normalized.includes('rain') || normalized.includes('drizzle')) return '🌧️';
  if (normalized.includes('snow') || normalized.includes('sleet')) return '❄️';
  if (normalized.includes('fog') || normalized.includes('mist') || normalized.includes('haze')) return '🌫️';
  if (normalized.includes('cloud')) return '☁️';
  if (normalized.includes('wind')) return '💨';
  if (normalized.includes('clear') || normalized.includes('sun')) return '☀️';
  return '🌡️';
}

function getWeatherVariant(condition: string): 'default' | 'success' | 'warning' | 'error' {
  const normalized = condition.toLowerCase();
  if (normalized.includes('rain') || normalized.includes('thunder') || normalized.includes('storm')) return 'error';
  if (normalized.includes('snow') || normalized.includes('fog') || normalized.includes('mist') || normalized.includes('cloud')) return 'default';
  if (normalized.includes('clear') || normalized.includes('sun')) return 'success';
  return 'warning';
}

function getDayLabel(day?: string, index?: number): string {
  if (day && day.trim()) return day;
  return `Day ${typeof index === 'number' ? index + 1 : 1}`;
}

function ForecastCard(props: { item: ForecastItem; index: number; unit: string; selectable?: boolean }) {
  const icon = props.item.icon && props.item.icon.trim() ? props.item.icon : getConditionIcon('');
  return (
    <Card
      as={props.selectable ? Clickable : undefined}
      padding="var(--ggui-spacing-3)"
      shadow="none"
      radius="md"
      border
      hoverStyle={props.selectable ? { opacity: 0.9 } : undefined}
    >
      <Stack gap="var(--ggui-spacing-2)" align="center">
        <Text variant="caption" weight="semibold" color="var(--ggui-color-onSurfaceVariant)" align="center">
          {getDayLabel(props.item.day, props.index)}
        </Text>
        <Text size="2xl" align="center" is="div">
          {icon}
        </Text>
        <Stack gap="var(--ggui-spacing-1)" align="center">
          <Text variant="bodySmall" weight="semibold" align="center">
            {typeof props.item.high === 'number' ? `${props.item.high}°${props.unit}` : `—°${props.unit}`}
          </Text>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" align="center">
            {typeof props.item.low === 'number' ? `${props.item.low}°${props.unit}` : `—°${props.unit}`}
          </Text>
        </Stack>
      </Stack>
    </Card>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const forecastItems = useMemo(() => (Array.isArray(props.forecast) ? props.forecast.slice(0, 5) : []), [props.forecast]);
  const currentIcon = useMemo(() => getConditionIcon(props.condition), [props.condition]);
  const weatherUnit = useMemo(() => ((props.unit || '').toUpperCase() === 'F' ? 'F' : 'C'), [props.unit]);
  const weatherVariant = useMemo(() => getWeatherVariant(props.condition), [props.condition]);
  const temperatureText = `${props.temperature}°${weatherUnit}`;
  const humidityText = `${props.humidity}%`;
  const windText = `${props.windSpeed}`;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card padding="var(--ggui-spacing-6)" shadow="md" radius="xl">
        <Stack gap="var(--ggui-spacing-6)">
          <Stack gap="var(--ggui-spacing-3)">
            <Row align="center" gap="var(--ggui-spacing-2)">
              <Badge variant={weatherVariant} size="lg">
                {props.condition}
              </Badge>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                {props.city}
              </Text>
            </Row>

            <Row align="end" gap="var(--ggui-spacing-4)">
              <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600)">
                {temperatureText}
              </Text>
              <Stack gap="var(--ggui-spacing-1)">
                <Text size="3xl" is="div">
                  {currentIcon}
                </Text>
                <Text variant="bodyLarge" weight="semibold">
                  {props.condition}
                </Text>
              </Stack>
            </Row>

            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Feels like current conditions in {props.city}.
            </Text>
          </Stack>

          <Divider margin="var(--ggui-spacing-2)" />

          <Row gap="var(--ggui-spacing-4)" wrap>
            <Card padding="var(--ggui-spacing-4)" shadow="none" radius="md" border>
              <Stack gap="var(--ggui-spacing-1)">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                <Text variant="bodyLarge" weight="bold">{humidityText}</Text>
              </Stack>
            </Card>
            <Card padding="var(--ggui-spacing-4)" shadow="none" radius="md" border>
              <Stack gap="var(--ggui-spacing-1)">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                <Text variant="bodyLarge" weight="bold">{windText}</Text>
              </Stack>
            </Card>
          </Row>

          <Divider margin="var(--ggui-spacing-2)" />

          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={4}>5-Day Forecast</Heading>
            <Row gap="var(--ggui-spacing-3)" wrap>
              {forecastItems.map((item, index) => (
                <ForecastCard
                  key={`${item.day ?? 'day'}-${index}`}
                  item={item}
                  index={index}
                  unit={weatherUnit}
                  selectable
                />
              ))}
            </Row>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim());
}

function getSatisfactionOptions(labels: string[]) {
  return Array.from({ length: 5 }, (_, index) => {
    const value = String(index + 1);
    return {
      value,
      label: labels[index] || `Rating ${value}`,
    };
  });
}

function getFeatureList(options: string[] | undefined) {
  return Array.isArray(options) ? options : [];
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [step, setStep] = React.useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [submitted, setSubmitted] = useState(false);
  const [touched, setTouched] = useState({ name: false, email: false });

  const satisfactionOptions = useMemo(() => getSatisfactionOptions(props.satisfactionLabels), [props.satisfactionLabels]);
  const featureOptions = useMemo(() => getFeatureList(props.featureOptions), [props.featureOptions]);

  const nameError = touched.name && !name.trim() ? 'Name is required.' : '';
  const emailError = touched.email && !email.trim() ? 'Email is required.' : touched.email && !isValidEmail(email) ? 'Enter a valid email address.' : '';
  const commentsCount = comments.length;
  const commentsError = commentsCount > 500 ? 'Comments must be 500 characters or fewer.' : '';

  const canGoNext = useMemo(() => {
    if (step === 1) {
      return !!name.trim() && isValidEmail(email);
    }
    if (step === 2) {
      return satisfaction !== '';
    }
    return true;
  }, [email, name, satisfaction, step]);

  const collectedPayload = useMemo<ActionSubmitPayload>(() => ({
    name: name.trim(),
    email: email.trim(),
    satisfaction: Number(satisfaction) || 0,
    features,
    comments: comments.slice(0, 500),
  }), [comments, email, features, name, satisfaction]);

  useEffect(() => {
    if (submitted) {
      setStep(4);
    }
  }, [submitted]);

  const goNext = useCallback(() => {
    if (step === 1) {
      setTouched({ name: true, email: true });
      if (!name.trim() || !isValidEmail(email)) return;
    }
    if (step === 2 && satisfaction === '') return;
    setStep((current) => Math.min(4, current + 1));
  }, [email, name, satisfaction, step]);

  const goBack = useCallback(() => {
    setStep((current) => Math.max(1, current - 1));
  }, []);

  const handleFeatureToggle = useCallback((feature: string, checked: boolean) => {
    setFeatures((current) => (checked ? Array.from(new Set([...current, feature])) : current.filter((item) => item !== feature)));
  }, []);

  const handleSubmit = useCallback(() => {
    submit(collectedPayload);
    setSubmitted(true);
  }, [collectedPayload, submit]);

  const stepTitle = step === 1 ? 'Your details' : step === 2 ? 'Satisfaction' : step === 3 ? 'Feature interests' : 'Comments';
  const progressValue = Math.min(100, (step / 4) * 100);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-5)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)">
            <Stack gap="var(--ggui-spacing-2)">
              <Row justify="between" align="center">
                <Heading level={2}>Multi-step survey</Heading>
                <Badge variant="primary">Step {step} of 4</Badge>
              </Row>
              <Text color="var(--ggui-color-onSurfaceVariant)">
                {stepTitle}
              </Text>
            </Stack>
            <Progress value={progressValue} max={100} showLabel size="md" />
            <Row gap="var(--ggui-spacing-2)" wrap>
              {Array.from({ length: 4 }, (_, index) => {
                const current = index + 1;
                const isActive = current === step;
                const isDone = current < step;
                return (
                  <Badge key={current} variant={isActive ? 'primary' : isDone ? 'success' : 'default'}>
                    {current === 1 ? 'Details' : current === 2 ? 'Satisfaction' : current === 3 ? 'Features' : 'Comments'}
                  </Badge>
                );
              })}
            </Row>
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm">
          <Stack gap="var(--ggui-spacing-5)">
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Step 1: Your details</Heading>
                <Input label="Name" value={name} onChange={setName} required error={nameError} placeholder="Enter your name" />
                <Input label="Email" type="email" value={email} onChange={setEmail} required error={emailError} placeholder="you@example.com" />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Step 2: Satisfaction rating</Heading>
                <RadioGroup
                  label="How satisfied are you?"
                  value={satisfaction}
                  onChange={setSatisfaction}
                  options={satisfactionOptions}
                  direction="vertical"
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Step 3: Feature interests</Heading>
                <Text color="var(--ggui-color-onSurfaceVariant)">Select all features you’re interested in.</Text>
                <Stack gap="var(--ggui-spacing-3)">
                  {featureOptions.length > 0 ? featureOptions.map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={features.includes(feature)}
                      onChange={(checked) => handleFeatureToggle(feature, checked)}
                    />
                  )) : (
                    <Alert variant="info" title="No feature options provided">
                      There are no feature interests to select.
                    </Alert>
                  )}
                </Stack>
              </Stack>
            )}

            {step === 4 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Step 4: Comments</Heading>
                <TextArea
                  label="Open-ended comments"
                  value={comments}
                  onChange={setComments}
                  placeholder="Share any extra feedback..."
                  rows={6}
                  maxLength={500}
                  showCount
                  helperText="Optional. Share anything else we should know."
                  error={commentsError}
                />
              </Stack>
            )}

            {step === 5 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Review & submit</Heading>
                <Card padding="var(--ggui-spacing-4)" shadow="none" border>
                  <Stack gap="var(--ggui-spacing-3)">
                    <Row justify="between" gap="var(--ggui-spacing-3)">
                      <Text weight="medium">Name</Text>
                      <Text>{collectedPayload.name || '—'}</Text>
                    </Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row justify="between" gap="var(--ggui-spacing-3)">
                      <Text weight="medium">Email</Text>
                      <Text>{collectedPayload.email || '—'}</Text>
                    </Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row justify="between" gap="var(--ggui-spacing-3)">
                      <Text weight="medium">Satisfaction</Text>
                      <Text>{satisfaction ? ((props.satisfactionLabels && props.satisfactionLabels[Number(satisfaction) - 1]) || `Rating ${satisfaction}`) : '—'}</Text>
                    </Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Stack gap="var(--ggui-spacing-2)">
                      <Text weight="medium">Feature interests</Text>
                      <Text color="var(--ggui-color-onSurfaceVariant)">
                        {features.length > 0 ? features.join(', ') : 'None selected'}
                      </Text>
                    </Stack>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Stack gap="var(--ggui-spacing-2)">
                      <Text weight="medium">Comments</Text>
                      <Text color="var(--ggui-color-onSurfaceVariant)">
                        {collectedPayload.comments || 'No comments provided'}
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
                <Row justify="between" align="center" gap="var(--ggui-spacing-3)" wrap>
                  <Button variant="outline" onClick={goBack}>Back</Button>
                  <Spacer size="flex" />
                  <Button variant="primary" onClick={handleSubmit}>Confirm and submit</Button>
                </Row>
              </Stack>
            )}

            {submitted && (
              <Alert variant="success" title="Survey submitted">
                Thanks for sharing your feedback. Your responses were sent successfully.
              </Alert>
            )}
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

