import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




function normalizeColumnId(column?: string): string {
  return column && column.trim() ? column : 'todo';
}

function getColumnName(columnId: string, columns: Props['columns']): string {
  const found = columns.find((column) => column.id === columnId);
  return found?.name || columnId;
}

function getPriorityVariant(priority?: 'low' | 'medium' | 'high'): 'default' | 'warning' | 'error' {
  if (priority === 'high') return 'error';
  if (priority === 'medium') return 'warning';
  return 'default';
}

function formatDueDate(dueDate?: string): string {
  if (!dueDate) return '';
  const parsed = new Date(dueDate);
  if (Number.isNaN(parsed.getTime())) return dueDate;
  return parsed.toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' });
}

function getInitials(name?: string): string {
  if (!name) return '??';
  const parts = name.trim().split(/\s+/).filter(Boolean);
  if (!parts.length) return '??';
  const initials = parts.slice(0, 2).map((part) => part[0] || '').join('');
  return (initials || name.slice(0, 2) || '??').toUpperCase();
}

function createTaskId(title: string): string {
  return `task-${Date.now()}-${Math.random().toString(36).slice(2, 8)}-${title.trim().toLowerCase().replace(/[^a-z0-9]+/g, '-') || 'new'}`;
}

function coerceTask(task: Props['tasks'][number], fallbackColumnId: string): Required<Pick<NonNullable<Props['tasks'][number]>, 'title' | 'priority' | 'assignee' | 'column'>> & { id: string; dueDate?: string } {
  return {
    id: task.id || createTaskId(task.title || 'task'),
    title: task.title || 'Untitled task',
    priority: task.priority || 'low',
    assignee: task.assignee || '',
    column: normalizeColumnId(task.column || fallbackColumnId),
    dueDate: task.dueDate,
  };
}

export default function Component(props: Props) {
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [draftTasks, setDraftTasks] = useState<Record<string, { title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string }>>({});
  const [newTaskTitle, setNewTaskTitle] = useState<Record<string, string>>({});
  const [newTaskPriority, setNewTaskPriority] = useState<Record<string, 'low' | 'medium' | 'high'>>({});
  const [addingColumnId, setAddingColumnId] = useState<string | null>(null);
  const [tasks, setTasks] = useState<Array<{ id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string }>>([]);

  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  const normalizedColumns = useMemo(() => (props.columns || []).map((column, index) => ({
    id: normalizeColumnId(column.id || (index === 0 ? 'todo' : index === 1 ? 'in-progress' : 'done')),
    name: column.name || getColumnName(normalizeColumnId(column.id || (index === 0 ? 'todo' : index === 1 ? 'in-progress' : 'done')), props.columns),
  })), [props.columns]);

  useEffect(() => {
    setTasks((props.tasks || []).map((task, index) => coerceTask(task, normalizedColumns[index % Math.max(1, normalizedColumns.length)]?.id || 'todo')));
  }, [props.tasks, normalizedColumns]);

  useEffect(() => {
    const latest = taskChanged.latest;
    if (!latest?.task) return;
    const incoming = coerceTask(latest.task, latest.task.column || 'todo');
    setTasks((current) => {
      const existingIndex = current.findIndex((task) => task.id === incoming.id);
      if (latest.action === 'delete') {
        return existingIndex >= 0 ? current.filter((task) => task.id !== incoming.id) : current;
      }
      if (existingIndex >= 0) {
        const next = [...current];
        next[existingIndex] = incoming;
        return next;
      }
      return [...current, incoming];
    });
  }, [taskChanged.latest]);

  const groupedTasks = useMemo(() => {
    const groups: Record<string, ReturnType<typeof coerceTask>[]> = {};
    normalizedColumns.forEach((column) => { groups[column.id] = []; });
    tasks.forEach((task) => {
      const columnId = normalizeColumnId(task.column);
      if (!groups[columnId]) groups[columnId] = [];
      groups[columnId].push(task);
    });
    return groups;
  }, [tasks, normalizedColumns]);

