    const priority = newTaskPriority[columnId] || 'low';
    const id = createTaskId(title);
    const newTask = { id, title, priority, assignee: '', column: normalizeColumnId(columnId) };
    setTasks((current) => [...current, newTask]);
    taskUpdate({ action: 'create', taskId: id, data: { column: normalizeColumnId(columnId) } });
    setNewTaskTitle((current) => ({ ...current, [columnId]: '' }));
    setNewTaskPriority((current) => ({ ...current, [columnId]: 'low' }));
