                  onClick={() => {
                    setEditing(false);
                    setDraftTitle(taskProps.task.title);
                  }}
                >
                  Cancel
                </Button>
                <Button
                  onClick={() => {
                    const nextTitle = draftTitle.trim() || 'Untitled task';
                    taskProps.onEdit(taskProps.task.id, nextTitle);
                    setEditing(false);
                  }}
                >
                  Save
                </Button>
              </Row>
            </Stack>
          ) : (
            <Stack gap="var(--ggui-spacing-2)">
              <Text as={Clickable} onClick={() => setEditing(true)} variant="bodyLarge" weight="semibold">
                {taskProps.task.title}
              </Text>
              <Button variant="ghost" size="sm" onClick={() => setEditing(true)}>
                Edit
              </Button>
            </Stack>
          )}
          <Row gap="var(--ggui-spacing-3)" align="center" justify="between">
            <Row gap="var(--ggui-spacing-2)" align="center">
              <Avatar name={taskProps.task.assignee || 'Unassigned'} size="sm" />
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                {taskProps.task.assignee || 'Unassigned'}
