                Due {formatDueDate(taskProps.task.dueDate)}
              </Text>
            ) : null}
          </Row>
        </Stack>
      </Card>
    );
  }, []);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Row align="center" justify="between" gap="var(--ggui-spacing-3)">
            <Heading level={2}>Task Board</Heading>
            <Row gap="var(--ggui-spacing-4)">
              <Badge variant="primary">Total {totals.total}</Badge>
              <Badge variant="success">Done {totals.done}</Badge>
            </Row>
          </Row>
        </Card>
        <Row gap="var(--ggui-spacing-4)" wrap align="start">
          {normalizedColumns.map((column) => (
            <Card key={column.id} padding="var(--ggui-spacing-4)" shadow="sm" radius="lg">
