function normalizeText(value: unknown): string {
  return typeof value === 'string' ? value : value == null ? '' : String(value);
}

function normalizeNumber(value: unknown, fallback = 0): number {
  const numeric = typeof value === 'number' ? value : Number(value);
  return Number.isFinite(numeric) ? numeric : fallback;
}

function formatCurrency(price: number, currency: string): string {
  try {
    return new Intl.NumberFormat(undefined, { style: 'currency', currency: currency || 'USD' }).format(price);
  } catch {
    return `${currency || 'USD'} ${price.toFixed(2)}`;
  }
}

function renderStars(rating: number) {
  const count = Math.max(0, Math.min(5, Math.round(rating)));
  return Array.from({ length: 5 }, (_, index) => (
    <Icon key={index} name="star" size={16} color={index < count ? 'var(--ggui-color-warning)' : 'var(--ggui-color-outline)'} />
  ));
}

function normalizeSpecs(specifications: unknown[] | undefined): Array<{ key: string; value: string }> {
  if (!Array.isArray(specifications)) return [];
  return specifications.map((item, index) => {
    if (item && typeof item === 'object') {
      const entries = Object.entries(item as Record<string, unknown>);
      if (entries.length >= 1) {
        const [key, value] = entries[0];
        return { key: normalizeText(key) || `spec-${index + 1}`, value: normalizeText(value) };
      }
    }
    return { key: `spec-${index + 1}`, value: normalizeText(item) };
  });
}

function normalizeReviews(reviews: unknown[] | undefined): Array<{ author: string; rating: number; text: string; date: string }> {
  if (!Array.isArray(reviews)) return [];
  return reviews.map((review, index) => {
    if (review && typeof review === 'object') {
      const record = review as Record<string, unknown>;
      return {
        author: normalizeText(record.author ?? record.name ?? `Reviewer ${index + 1}`),
        rating: normalizeNumber(record.rating),
        text: normalizeText(record.text ?? record.content ?? record.body),
        date: normalizeText(record.date ?? record.createdAt ?? record.timestamp),
      };
    }
    return { author: `Reviewer ${index + 1}`, rating: 0, text: normalizeText(review), date: '' };
  });
}

