function normalizeTimestamp(value?: string): string {
  if (!value) return '';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  return new Intl.DateTimeFormat(undefined, {
    hour: '2-digit',
    minute: '2-digit',
  }).format(date);
}

function createMessage(sender: string, text: string, timestamp?: string) {
  return {
    id: `${sender}-${timestamp ?? 'stream'}-${text}`,
    sender,
    text,
    timestamp: timestamp ?? new Date().toISOString(),
  };
}

function groupMessagesBySender(messages: Array<{ sender?: string; text?: string; timestamp?: string }>) {
  const groups: Array<{
    sender: string;
    items: Array<{ sender?: string; text?: string; timestamp?: string }>;
  }> = [];
  messages.forEach((message, index) => {
    const sender = message.sender ?? 'Unknown';
    const last = groups[groups.length - 1];
    if (last && last.sender === sender) {
      last.items.push(message);
    } else {
      groups.push({ sender, items: [message] });
    }
  });
  return groups;
}

export default function Component(props: Props) {
