  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [draft, setDraft] = useState('');
  const [messages, setMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages ?? []);
  const [isTyping, setIsTyping] = useState(false);
  const listEndRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setMessages(props.messages ?? []);
  }, [props.messages]);

  useEffect(() => {
    if (message.latest?.sender || message.latest?.text || message.latest?.timestamp) {
      setMessages((current) => [...current, message.latest as StreamMessage]);
    }
  }, [message.latest]);

  const typingState = useMemo(() => {
    const typingEvents = typing.all ?? [];
    let active = false;
    let sender = '';
    typingEvents.forEach((event) => {
      if (!event || event.sender === props.currentUser) return;
      sender = event.sender ?? sender;
      active = Boolean(event.active);
    });
    return { active, sender };
  }, [typing.all, props.currentUser]);

  useEffect(() => {
    setIsTyping(typingState.active);
