              >
                <Stack gap="var(--ggui-spacing-3)">
                  {groupedMessages.length === 0 ? (
                    <Box padding="var(--ggui-spacing-4)">
                      <Text color="var(--ggui-color-onSurfaceVariant)">No messages yet. Start the conversation.</Text>
                    </Box>
                  ) : (
                    groupedMessages.map((group, groupIndex) => (
                      <Stack key={`${group.sender}-${groupIndex}`} gap="var(--ggui-spacing-2)">
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{group.sender}</Text>
                        {group.items.map((item, itemIndex) => {
                          const isOwn = item.sender === props.currentUser;
                          const nextItem = group.items[itemIndex + 1];
                          const showSeparator = Boolean(nextItem) && nextItem.sender === item.sender;
                          return (
                            <Row
                              key={`${item.sender ?? 'unknown'}-${item.timestamp ?? itemIndex}-${item.text ?? ''}`}
                              align="center"
                              justify={isOwn ? 'end' : 'start'}
                              style={{ marginBottom: showSeparator ? 'var(--ggui-spacing-1)' : '0' }}
                            >
