                                borderRadius="var(--ggui-shape-radius-lg)"
                                style={{
                                  maxWidth: 'min(80%, 640px)',
                                  color: isOwn ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurface)',
                                }}
                              >
                                <Stack gap="var(--ggui-spacing-1)">
                                  <Row align="center" justify="between" gap="var(--ggui-spacing-2)">
                                    <Text variant="label" color={isOwn ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurface)'}>{item.sender ?? 'Unknown'}</Text>
                                    <Text variant="caption" color={isOwn ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurfaceVariant)'}>{normalizeTimestamp(item.timestamp)}</Text>
