function formatPrice(value?: number): string {
  if (typeof value !== 'number' || Number.isNaN(value)) {
    return '--';
  }
  return value.toFixed(2);
}

function formatSignedNumber(value?: number, digits = 2): string {
  if (typeof value !== 'number' || Number.isNaN(value)) {
    return '--';
  }
  const formatted = Math.abs(value).toFixed(digits);
  return value > 0 ? `+${formatted}` : value < 0 ? `-${formatted}` : formatted;
}

function formatTimestamp(date: Date): string {
  return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
}

function mergeStocks(
  baseStocks: Props['stocks'],
  update?: StreamPriceUpdate | null,
): Props['stocks'] {
  if (!update?.symbol) {
    return baseStocks ?? [];
  }

  const incoming = baseStocks ?? [];
  const existingIndex = incoming.findIndex((stock) => stock?.symbol === update.symbol);
  const nextStock = existingIndex >= 0 ? incoming[existingIndex] : { symbol: update.symbol };
  const mergedStock = {
    ...nextStock,
    symbol: update.symbol,
    price: typeof update.price === 'number' ? update.price : nextStock?.price,
    change: typeof update.change === 'number' ? update.change : nextStock?.change,
    changePercent:
      typeof update.changePercent === 'number' ? update.changePercent : nextStock?.changePercent,
  };

  if (existingIndex < 0) {
    return [mergedStock, ...incoming];
  }

  return incoming.map((stock, index) => (index === existingIndex ? mergedStock : stock));
}

