interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





const THEME_CHOICES = [
  { value: 'light', label: 'Light' },
  { value: 'dark', label: 'Dark' },
];

function isValidEmail(email: string) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim());
}

function getStepLabel(step: number) {
  return `${step}/3`;
}

function StepPill(props: { active: boolean; completed: boolean; step: number; label: string }) {
  return (
    <Box
      padding="var(--ggui-spacing-3)"
      background={props.active ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surfaceVariant)'}
      borderRadius="var(--ggui-shape-radius-lg)"
    >
      <Stack gap="var(--ggui-spacing-1)">
        <Row align="center" justify="between">
          <Badge variant={props.completed ? 'success' : props.active ? 'primary' : 'default'} size="sm">
            Step {props.step}
          </Badge>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            {props.completed ? 'Completed' : props.active ? 'In progress' : 'Pending'}
          </Text>
        </Row>
        <Heading level={6}>{props.label}</Heading>
      </Stack>
    </Box>
  );
}

function SummaryRow(props: { label: string; value: React.ReactNode }) {
  return (
    <Row justify="between" align="start" gap="var(--ggui-spacing-4)">
      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{props.label}</Text>
      <Text variant="bodySmall" weight="medium" align="right">{props.value}</Text>
    </Row>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile.name ?? '');
  const [email, setEmail] = useState(props.initialProfile.email ?? '');
  const [avatar, setAvatar] = useState(props.initialProfile.avatar ?? props.avatarOptions[0] ?? '😀');
  const [role, setRole] = useState(props.initialProfile.role ?? props.roleOptions[0] ?? 'Developer');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile.theme ?? 'light');
  const [direction, setDirection] = useState<'forward' | 'backward' | null>(null);

  useEffect(() => {
    setName(props.initialProfile.name ?? '');
    setEmail(props.initialProfile.email ?? '');
    setAvatar(props.initialProfile.avatar ?? props.avatarOptions[0] ?? '😀');
    setRole(props.initialProfile.role ?? props.roleOptions[0] ?? 'Developer');
    setEmailNotifications(props.initialProfile.emailNotifications ?? true);
    setTheme(props.initialProfile.theme ?? 'light');
    setStep(1);
  }, [props.initialProfile, props.avatarOptions, props.roleOptions]);

  const nameError = name.trim() ? '' : 'Name is required.';
  const emailError = !email.trim() ? 'Email is required.' : isValidEmail(email) ? '' : 'Enter a valid email address.';
  const canGoNext = step === 1 ? !nameError && !emailError : true;

  const avatarCount = Math.max(props.avatarOptions.length, 1);
  const progressValue = ((step - 1) / 2) * 100;
  const transitionStyle = useMemo<React.CSSProperties>(() => ({
    animation: 'ggui-fadeIn 200ms ease-out',
    transition: 'opacity 200ms ease-in-out, transform 200ms ease-in-out',
  }), [step]);

  const summary = useMemo(() => ({ name: name.trim(), email: email.trim(), avatar, role, emailNotifications, theme }), [name, email, avatar, role, emailNotifications, theme]);

  const goNext = useCallback(() => {
    if (step < 3 && canGoNext) {
      setDirection('forward');
      setStep((current) => Math.min(3, current + 1));
    }
  }, [step, canGoNext]);

  const goBack = useCallback(() => {
    if (step > 1) {
      setDirection('backward');
      setStep((current) => Math.max(1, current - 1));
    }
  }, [step]);

  const submit = useCallback(() => {
    if (!name.trim() || !isValidEmail(email)) {
      setStep(1);
      return;
    }
    complete({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  }, [complete, name, email, avatar, role, emailNotifications, theme]);

  const stepContent = (() => {
    if (step === 1) {
      return (
        <Stack gap="var(--ggui-spacing-4)" style={transitionStyle}>
          <Stack gap="var(--ggui-spacing-3)">
            <Input label="Full name" value={name} onChange={setName} required error={nameError || undefined} placeholder="Your name" />
            <Input label="Email address" type="email" value={email} onChange={setEmail} required error={emailError || undefined} placeholder="you@example.com" />
          </Stack>
          <Box>
            <Text variant="label">Choose an avatar</Text>
            <Row gap="var(--ggui-spacing-3)" wrap style={{ marginTop: 'var(--ggui-spacing-2)' }}>
              {props.avatarOptions.map((choice, index) => (
                <Button
                  key={choice}
                  variant={avatar === choice ? 'primary' : 'outline'}
                  size="sm"
                  onClick={() => setAvatar(choice)}
                  aria-label={`Select avatar ${choice}`}
                  leftIcon={<Text is="span" size="xl">{choice}</Text>}
                >
                  Avatar {index + 1}
                </Button>
              ))}
            </Row>
          </Box>
        </Stack>
      );
    }
    if (step === 2) {
      return (
        <Stack gap="var(--ggui-spacing-4)" style={transitionStyle}>
          <Select
            label="Role"
            value={role}
            onChange={setRole}
            options={props.roleOptions.map((option) => ({ value: option, label: option }))}
            helperText="Select the role that best matches how you use the app."
          />
          <Stack gap="var(--ggui-spacing-3)">
            <Checkbox
              label="Email notifications"
              checked={emailNotifications}
              onChange={setEmailNotifications}
              description="Receive onboarding updates and important account messages by email."
            />
            <Toggle
              label="Dark theme"
              checked={theme === 'dark'}
              onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
            />
          </Stack>
        </Stack>
      );
    }
    return (
      <Stack gap="var(--ggui-spacing-4)" style={transitionStyle}>
        <Alert variant="info" title="Review your details">
          Please confirm your profile information before completing setup.
        </Alert>
        <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg">
          <Stack gap="var(--ggui-spacing-3)">
            <SummaryRow label="Name" value={summary.name || '—'} />
            <Divider margin="var(--ggui-spacing-2)" />
            <SummaryRow label="Email" value={summary.email || '—'} />
            <Divider margin="var(--ggui-spacing-2)" />
            <SummaryRow label="Avatar" value={<span aria-label="avatar">{summary.avatar}</span>} />
            <Divider margin="var(--ggui-spacing-2)" />
            <SummaryRow label="Role" value={summary.role} />
            <Divider margin="var(--ggui-spacing-2)" />
            <SummaryRow label="Email notifications" value={summary.emailNotifications ? 'On' : 'Off'} />
            <Divider margin="var(--ggui-spacing-2)" />
            <SummaryRow label="Theme" value={summary.theme === 'dark' ? 'Dark' : 'Light'} />
          </Stack>
        </Card>
      </Stack>
    );
  })();

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      {/* motion keyframes not required in this build */}
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="xl">
          <Stack gap="var(--ggui-spacing-5)">
            <Stack gap="var(--ggui-spacing-2)">
              <Row justify="between" align="center">
                <Heading level={2}>Onboarding wizard</Heading>
                <Badge variant="primary">{getStepLabel(step)}</Badge>
              </Row>
              <Text color="var(--ggui-color-onSurfaceVariant)">Complete your profile in three quick steps.</Text>
              <Progress value={progressValue} max={100} size="md" showLabel />
            </Stack>

            <Row gap="var(--ggui-spacing-3)" wrap>
              <Box style={{ flex: '1 1 220px' }}><StepPill step={1} label="Profile Setup" active={step === 1} completed={step > 1} /></Box>
              <Box style={{ flex: '1 1 220px' }}><StepPill step={2} label="Preferences" active={step === 2} completed={step > 2} /></Box>
              <Box style={{ flex: '1 1 220px' }}><StepPill step={3} label="Review & Confirm" active={step === 3} completed={false} /></Box>
            </Row>

            <Divider />

            <Box style={{ animation: direction === 'backward' ? 'ggui-slideInDown 200ms ease-out' : 'ggui-slideInUp 200ms ease-out' }}>
              {stepContent}
            </Box>

            <Divider />

            <Row justify="between" align="center" wrap gap="var(--ggui-spacing-3)">
              <Button variant="outline" onClick={goBack} disabled={step === 1}>Go Back</Button>
              <Spacer size="flex" />
              {step < 3 ? (
                <Button variant="primary" onClick={goNext} disabled={!canGoNext}>Next</Button>
              ) : (
                <Button variant="primary" onClick={submit}>Complete Setup</Button>
              )}
            </Row>
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg">
          <Stack gap="var(--ggui-spacing-2)">
            <Heading level={4}>Current selections</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Editing existing profile values is supported; changes update the review step instantly.
            </Text>
            <Row gap="var(--ggui-spacing-2)" wrap>
              <Tag variant={summary.name ? 'success' : 'warning'}>{summary.name ? 'Name set' : 'Name missing'}</Tag>
              <Tag variant={summary.email && !emailError ? 'success' : 'warning'}>{summary.email && !emailError ? 'Email valid' : 'Email needs attention'}</Tag>
              <Tag variant="primary">{summary.avatar}</Tag>
              <Tag variant="default">{summary.role}</Tag>
              <Tag variant={summary.emailNotifications ? 'success' : 'default'}>{summary.emailNotifications ? 'Notifications on' : 'Notifications off'}</Tag>
              <Tag variant={summary.theme === 'dark' ? 'info' : 'default'}>{summary.theme === 'dark' ? 'Dark theme' : 'Light theme'}</Tag>
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}
